import{_ as t,o,c as a,a2 as i}from"./chunks/framework.CKCxdkvf.js";const m=JSON.parse('{"title":"RFC-013 — ISS Explorer · 3D model pipeline & module pickability","description":"","frontmatter":{},"headers":[],"relativePath":"rfc/RFC-013.md","filePath":"rfc/RFC-013.md"}'),r={name:"rfc/RFC-013.md"};function s(l,e,d,n,c,h){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="rfc-013-—-iss-explorer-·-3d-model-pipeline-module-pickability" tabindex="-1">RFC-013 — ISS Explorer · 3D model pipeline &amp; module pickability <a class="header-anchor" href="#rfc-013-—-iss-explorer-·-3d-model-pipeline-module-pickability" aria-label="Permalink to &quot;RFC-013 — ISS Explorer · 3D model pipeline &amp; module pickability&quot;">​</a></h1><p><em>Orrery · Closed RFC · v0.1 · May 2026</em></p><blockquote><p><strong>Status:</strong> Closed (accepted 2026-05-05 — ADR-040, ADR-041, ADR-042) <strong>Author:</strong> product <strong>Closes into:</strong> ADR-040 (model source + asset pipeline), ADR-041 (module-pick strategy + LOD), ADR-042 (low-end-device fallback) <strong>Slice gate:</strong> v0.4 <strong>Why this is an RFC:</strong> PRD-010 promises a rotatable 3D ISS where every module is clickable, panelled, and historically attributed. The technical questions cluster around the <em>model</em> (where do we get a 3D ISS that&#39;s accurate, cleanly licensed, and small enough to ship?), <em>picking</em> (mesh-per-module is conceptually clean but explodes the tris budget — what&#39;s the right granularity?), and <em>fallback</em> (we promised a low-end-device path; is that a list view, a 2D diagram, or a simplified 3D model?).</p></blockquote><hr><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The ISS is the largest, most complex, longest-occupied human spacecraft ever flown. Existing 3D model resources:</p><ul><li><strong>NASA-3D Resources</strong> — multiple official ISS GLTF / OBJ models, NASA Open Source Agreement (close to public-domain).</li><li><strong>NASA Eyes on the Solar System</strong> — high-fidelity model used in NASA&#39;s WebGL apps; not directly redistributable.</li><li><strong>Wikimedia Commons / Sketchfab community</strong> — many community models, mixed quality and licences (CC-BY most common).</li><li><strong>Custom Blender authoring</strong> — ~3 weeks to author a low-poly station from reference photos.</li></ul><p>PRD-010 wants:</p><ul><li>16 pressurised modules individually clickable</li><li>&lt; 4 MB compressed initial load</li><li>Renders at ≥ 30 fps on 2020-baseline mobile</li><li>Visually faithful to the reference photo (the audience knows what the ISS looks like)</li><li>Dark-theme native (matte white module skins, gold MLI, blue solar panels)</li></ul><p>These are achievable but not trivially. The tris budget alone is the first hard constraint.</p><hr><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><h3 id="oq-1-—-where-does-the-model-come-from" tabindex="-1">OQ-1 — Where does the model come from? <a class="header-anchor" href="#oq-1-—-where-does-the-model-come-from" aria-label="Permalink to &quot;OQ-1 — Where does the model come from?&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Source</th><th>Licence</th><th>Tris budget</th><th>Authoring cost</th></tr></thead><tbody><tr><td><strong>A. NASA-3D Resources GLB, simplified</strong></td><td>NASA repo, Blender decimation pass</td><td>NASA Open Source Agreement (very permissive)</td><td>Original ~500k tris → simplified to ~50k</td><td>~3 days simplification + cleanup</td></tr><tr><td><strong>B. Custom Blender model from scratch</strong></td><td>Hand-authored</td><td>Project-owned (cleanest)</td><td>Target ~30k tris</td><td>~3 weeks</td></tr><tr><td><strong>C. Sketchfab / community CC-BY</strong></td><td>Community model with commercial redistribution licence</td><td>CC-BY (with attribution)</td><td>Variable</td><td>~1 day import + cleanup</td></tr><tr><td><strong>D. Procedural — generate cylinders + boxes for modules from spec</strong></td><td>Code-driven from <code>iss-modules.json</code></td><td>Project-owned</td><td>~5k tris</td><td>~2 days authoring + spec</td></tr></tbody></table><p><strong>Recommendation: A.</strong> NASA-3D Resources is the cleanest pedigree for an <em>accurate</em> model; the licence is permissive; the simplification pass is well-trodden Blender work. Option D is tempting (procedural would be an instant fallback for OQ-3) but produces a &quot;block diagram&quot; rather than the recognisable station — fails the &quot;audience knows what the ISS looks like&quot; test.</p><p>The simplified GLB ships at <code>static/models/iss/iss-low.glb</code>; original-source attribution recorded in <code>static/models/iss/CREDITS.md</code> per PA §principles.</p><hr><h3 id="oq-2-—-module-pickability-mesh-per-module-or-pick-atlas" tabindex="-1">OQ-2 — Module pickability: mesh-per-module or pick atlas? <a class="header-anchor" href="#oq-2-—-module-pickability-mesh-per-module-or-pick-atlas" aria-label="Permalink to &quot;OQ-2 — Module pickability: mesh-per-module or pick atlas?&quot;">​</a></h3><p>PRD-010 wants 16 modules individually clickable. There are two architectural options.</p><table tabindex="0"><thead><tr><th>Option</th><th>How it works</th><th>Tris cost</th><th>Per-module operations</th><th>Memory</th></tr></thead><tbody><tr><td><strong>A. Mesh-per-module</strong></td><td>Each module is a separate <code>THREE.Mesh</code> in a Group; Raycaster intersects against the module list</td><td>+0 (same total geometry, just split)</td><td>Trivial (<code>mesh.userData.moduleId</code>)</td><td>One draw call per module = 16 draw calls vs ~1</td></tr><tr><td><strong>B. Single mesh + UV pick atlas</strong></td><td>One unified mesh; a colour-coded atlas texture marks each module&#39;s UV island; pick by reading the picked pixel&#39;s colour</td><td>-0 (single mesh, single draw call)</td><td>Read pixel from offscreen render; map colour → moduleId</td><td>One draw call but offscreen-render-on-pick adds latency</td></tr><tr><td><strong>C. Mesh-per-module + truss as one merged mesh</strong></td><td>Hybrid: pressurised modules individual; trusses + arrays merged</td><td>+0</td><td>Same as A</td><td>~17 draw calls (16 modules + 1 truss complex)</td></tr></tbody></table><p><strong>Recommendation: C.</strong> Mesh-per-pressurised-module gives the click target. Trusses + solar arrays are visual scenery in V1 (PRD-010 explicitly defers per-truss pickability) and can be a single merged mesh. Total ~17 draw calls is well within budget.</p><hr><h3 id="oq-3-—-low-end-device-fallback-prd-010-§scope-§technical" tabindex="-1">OQ-3 — Low-end-device fallback (PRD-010 §scope §technical) <a class="header-anchor" href="#oq-3-—-low-end-device-fallback-prd-010-§scope-§technical" aria-label="Permalink to &quot;OQ-3 — Low-end-device fallback (PRD-010 §scope §technical)&quot;">​</a></h3><p>PRD-010 promises <code>?view=list</code> falls back to an alphabetical list with the same panel structure. Implementation question: how do we <em>detect</em> a low-end device, and what does &quot;list mode&quot; look like exactly?</p><table tabindex="0"><thead><tr><th>Option</th><th>Detection</th><th>List UX</th></tr></thead><tbody><tr><td><strong>A. URL-only (<code>?view=list</code>)</strong></td><td>User opt-in or default for known-bad UA</td><td>Alphabetical list of cards; tap → panel</td></tr><tr><td><strong>B. URL + heuristic auto-fallback</strong></td><td>If WebGL not supported OR <code>navigator.deviceMemory &lt; 4</code> OR initial render &lt; 20 fps → switch to list automatically</td><td>Same list UX</td></tr><tr><td><strong>C. URL + a small &quot;switch to list view&quot; toast</strong></td><td>Render an &quot;if 3D is slow, switch to list&quot; banner the first time the user lands; dismissed via toast</td><td>Same list UX</td></tr></tbody></table><p><strong>Recommendation: A + B combined.</strong> URL parameter is the explicit override. Heuristic auto-fallback (no WebGL, low memory, or sustained sub-20 fps after 2 seconds) flips to list view automatically. C is a polish-pass that we can layer on later.</p><p>ADR-042 records the detection rules so they&#39;re testable.</p><hr><h3 id="oq-4-—-earth-backdrop-in-v1" tabindex="-1">OQ-4 — Earth backdrop in V1? <a class="header-anchor" href="#oq-4-—-earth-backdrop-in-v1" aria-label="Permalink to &quot;OQ-4 — Earth backdrop in V1?&quot;">​</a></h3><p>PRD-010 V1 commits to a black-space backdrop with Earth deferred to V1.5. Worth re-checking: a faint Earth limb behind the station is visually striking and reinforces &quot;low-Earth orbit.&quot; Cost is small (sphere + texture, no animation).</p><table tabindex="0"><thead><tr><th>Option</th><th>Cost</th><th>Risk</th></tr></thead><tbody><tr><td><strong>A. Black space backdrop only (per PRD)</strong></td><td>0</td><td>Visual feels disembodied</td></tr><tr><td><strong>B. Static Earth limb at the bottom of the viewport</strong></td><td>+1 day</td><td>Adds 1 sphere + a 2K texture (~1.5 MB compressed); some performance hit on low-end</td></tr><tr><td><strong>C. Animated Earth (slow rotation matching real ISS orbital period scaled down)</strong></td><td>+2 days</td><td>Distracts from the model</td></tr></tbody></table><p><strong>Recommendation: B for V1.</strong> A static Earth limb is a 90% visual win for a 10% cost. Ship it with the existing <code>2k_earth_daymap.jpg</code> asset (same as <code>/earth</code> / <code>/explore</code>). Place it permanently below the station&#39;s centre of mass; the user always sees the station &quot;above&quot; Earth as in canonical photos.</p><hr><h3 id="oq-5-—-truss-segments-pickable-in-v1" tabindex="-1">OQ-5 — Truss segments pickable in V1? <a class="header-anchor" href="#oq-5-—-truss-segments-pickable-in-v1" aria-label="Permalink to &quot;OQ-5 — Truss segments pickable in V1?&quot;">​</a></h3><p>PRD-010 V1 commits to pressurised modules pickable, trusses non-pickable. The truss has its own engineering history (P0–P6, S0–S6, Canadarm2). User research note: most casual users don&#39;t ask about specific truss segments by name; they ask about Canadarm.</p><table tabindex="0"><thead><tr><th>Option</th><th>V1 scope</th></tr></thead><tbody><tr><td><strong>A. Trusses non-pickable (PRD V1)</strong></td><td>Pressurised modules only</td></tr><tr><td><strong>B. Canadarm2 separately pickable, trusses still grouped</strong></td><td>+1 module to clickable list</td></tr><tr><td><strong>C. Per-segment trusses</strong></td><td>+12 click targets — overkill for V1</td></tr></tbody></table><p><strong>Recommendation: B.</strong> Canadarm2 is iconic enough to deserve its own panel (history: built by MDA / CSA in 2001, the only Canadian-engineered piece on the station, used for every visiting-vehicle capture). Per-segment trusses defer to V2.</p><hr><h3 id="oq-6-—-lod-level-of-detail-strategy" tabindex="-1">OQ-6 — LOD (level of detail) strategy <a class="header-anchor" href="#oq-6-—-lod-level-of-detail-strategy" aria-label="Permalink to &quot;OQ-6 — LOD (level of detail) strategy&quot;">​</a></h3><p>A 50k-tri model at 60 fps on a 2020 phone is achievable but tight. LOD = swap to a lower-poly version when zoomed out.</p><table tabindex="0"><thead><tr><th>Option</th><th>Cost</th><th>Benefit</th></tr></thead><tbody><tr><td><strong>A. Single LOD</strong> (one model at all distances)</td><td>0</td><td>Simplest</td></tr><tr><td><strong>B. Two-level LOD</strong> — full at near, ~10k-tri version at far</td><td>+1 day authoring + Three.js LOD plumbing</td><td>Smoother low-end performance</td></tr><tr><td><strong>C. Three-level LOD</strong></td><td>+2 days</td><td>Marginal gain over B</td></tr></tbody></table><p><strong>Recommendation: A for V1, B for V1.1 if perf metrics fall short.</strong> Three.js&#39;s built-in LOD is straightforward to add later. Don&#39;t optimise prematurely.</p><hr><h3 id="oq-7-—-where-does-iss-sit-in-the-nav" tabindex="-1">OQ-7 — Where does ISS sit in the nav? <a class="header-anchor" href="#oq-7-—-where-does-iss-sit-in-the-nav" aria-label="Permalink to &quot;OQ-7 — Where does ISS sit in the nav?&quot;">​</a></h3><p>Current nav (post v0.4 + new pages from PRD-009): <code>EXPLORE → MISSIONS → PLAN → FLY → EARTH → MOON → MARS</code>.</p><p>Adding ISS:</p><ul><li>After EARTH (preserves &quot;LEO context&quot; — Earth then ISS in LEO)</li><li>Before EARTH (treat ISS as a <em>thing in space</em>, distinct from &quot;the Earth screen&quot;)</li><li>After MARS (keeps the planetary cluster intact, ISS as the tail)</li></ul><p><strong>Recommendation: After EARTH.</strong> Final order: <code>EXPLORE → MISSIONS → PLAN → FLY → EARTH → ISS → MOON → MARS</code>. ISS is in LEO; placing it next to /earth groups them as the &quot;near-Earth&quot; cluster. The simulator screens (PLAN/FLY) live before, the destination catalogue (MOON/MARS) lives after.</p><p>ADR-040 to lock the nav order alongside the asset-pipeline decision.</p><hr><h2 id="decision-criteria" tabindex="-1">Decision criteria <a class="header-anchor" href="#decision-criteria" aria-label="Permalink to &quot;Decision criteria&quot;">​</a></h2><p>We accept the resolution when:</p><ol><li>The 3D model loads in &lt; 4 MB compressed (gzipped GLB).</li><li>Initial render reaches ≥ 30 fps on a baseline 2020 mobile device (Pixel 4 / iPhone 11 / Galaxy A50 class).</li><li>All 16 pressurised modules + Canadarm2 are individually pickable with no false-positives on the truss complex.</li><li><code>?view=list</code> fallback path renders all panel content without WebGL.</li><li>Heuristic auto-fallback flips to list view without flicker on detected low-end devices.</li><li>Earth backdrop (if shipped) doesn&#39;t crash low-end devices.</li><li>Model + texture credits are recorded in <code>CREDITS.md</code> per PA §principles.</li></ol><hr><h2 id="closure-path" tabindex="-1">Closure path <a class="header-anchor" href="#closure-path" aria-label="Permalink to &quot;Closure path&quot;">​</a></h2><ul><li><strong>ADR-040</strong> — Asset pipeline: diagrammatic proxy + optional future NASA GLB swap-in. Earth backdrop using existing <code>2k_earth_daymap.jpg</code>. Nav slot after EARTH.</li><li><strong>ADR-041</strong> — Module pickability: mesh-per-pressurised-module + Canadarm2 + merged-truss. ~17 draw calls.</li><li><strong>ADR-042</strong> — Low-end-device fallback: <code>?view=list</code> URL override + heuristic auto-fallback (no WebGL, low memory, sustained sub-20 fps).</li></ul><p>Multi-LOD (OQ-6 option B), per-truss pickability (OQ-5 option C), animated Earth (OQ-4 option C) all deferred to V1.5 / V2.</p><hr><p><em>Orrery · RFC-013 · v0.1 · Closed.</em></p>',59)])])}const u=t(r,[["render",s]]);export{m as __pageData,u as default};
